def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 4 == 0:
                multiplier *= 1.03 + 0.012 * j
            elif j % 6 == 0:
                multiplier *= 0.92 - 0.007 * j
            else:
                multiplier *= 1.005
            if ratio < 0.08 * j:
                score += (j ** 3) / (1 + np.exp(ratio * j * 0.85)) * multiplier
            else:
                score += (np.log1p(j*j*j) + ratio**4) * multiplier / (j + 3)
            if (cap + j*j*j) % 11 == 0:
                score *= 1.07
            elif (cap * j) % 13 == 0:
                score *= 0.93
            if j == 8:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff*0.5)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.12 + 0.025 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.85 - 0.015 * j
            if j % 7 == 2 and cap % (j+2) == 0:
                penalty += np.sin(j * ratio * 1.3) * 0.6
            elif j % 5 == 1 and cap % (j+1) == 0:
                penalty -= np.cos(j * ratio * 0.8) * 0.4
            if j % 2 == 1:
                complexity += 1.0 / (j + 1) + np.tanh(ratio * j)
            else:
                complexity -= 0.5 / (j + 2)
        score += penalty * 0.85
        score *= adjustment * complexity
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.1)
            if cap % 3 == 0:
                priorities[i] *= 0.97
            else:
                priorities[i] *= 1.03
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1.2) * (1 + ratio*1.05)
                if ratio > 1.2:
                    priorities[i] *= 1.02
                else:
                    priorities[i] *= 0.99
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.1)
                if cap % 4 == 0:
                    priorities[i] *= 1.04
                else:
                    priorities[i] *= 0.96
        if ratio > 1.4:
            priorities[i] *= 1.2
        elif ratio < 0.04:
            priorities[i] *= 0.7
        if cap % 2 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.05
        if i % 3 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
